private UBSReferencing getUBSReferencing(TableId _tableId, RecId _recId)
{
    if(_tableId != tableNum(VendTable))
    {
        throw Error(strFmt("@SYS112754",_tableId));
    }

    return DirPartyTable::findRec(VendTable::findRecId(_recId).Party).UBSReferencing;
}

public UBSReferencing parmUBSReferencing(CompanyId _companyId,TableId _tableId, RecId _recId)
{
    return this.getUBSReferencing(_tableId,_recId);
}

private UBSEcoResCategoryName getUBSProcCategoryName(TableId _tableId, RecId _recId)
{
    if(_tableId != tableNum(VendTable))
    {
        throw Error(strFmt("@SYS112754",_tableId));
    }

    return DirPartyTable::findRec(VendTable::findRecId(_recId).Party).UBSProcCategoryName;
}
